function solve(n: number, edges: number[][], label: string): number {
    // Build adjacency list
    const graph: Map<number, number[]> = new Map();
    for (const [u, v] of edges) {
        if (!graph.has(u)) graph.set(u, []);
        if (!graph.has(v)) graph.set(v, []);
        graph.get(u)!.push(v);
        graph.get(v)!.push(u);
    }

    let maxLength = 0;

    // DFS to find the longest palindrome path
    function dfs(node: number, visited: Set<number>, path: string[]): void {
        visited.add(node);
        path.push(label[node]);

        // Check if current path is a palindrome
        if (path === path.slice().reverse()) {
            maxLength = Math.max(maxLength, path.length);
        }

        // Explore neighbors
        if (graph.has(node)) {
            for (const neighbor of graph.get(node)!) {
                if (!visited.has(neighbor)) {
                    dfs(neighbor, visited, path);
                }
            }
        }

        visited.delete(node);
        path.pop();
    }

    // Try each node as starting point
    for (let start = 0; start < n; start++) {
        const visited = new Set<number>();
        visited.add(start);
        const path: string[] = [label[start]];
        dfs(start, visited, path);
    }

    return maxLength;
}
